// Input-Validierung und Extraktion
const body = $input.first().json.body;

if (
  !body.submittedAnswer ||
  !body.description ||
  !body.categoryId
) {
  throw new Error(
    'Fehlende Parameter: submittedAnswer, description und categoryId sind erforderlich'
  );
}

const {
  submittedAnswer,
  description,
  categoryId
} = body;

// System-Prompt für KI
const systemPrompt = `
Du bist eine erfahrene Lehrkraft für die gymnasiale Oberstufe.
Deine Aufgabe ist es, Schülerantworten fachlich korrekt, fair und konstruktiv zu bewerten.

WICHTIG:
- Bewerte INHALTLICH und METHODISCH
- Keine Programmierung
- Kein Code
- Keine Lösungen ergänzen
- Keine neuen Aufgaben stellen

ANTWORTE NUR MIT EINEM VALIDEN JSON-OBJEKT, OHNE ZUSÄTZLICHEN TEXT!
`.trim();

// User-Prompt für KI
const userPrompt = `
Bewerte die folgende Schülerantwort zur gegebenen Aufgabenstellung.

### Aufgabenstellung:
${description}

### Schülerantwort:
${submittedAnswer}

Erstelle eine Bewertung im EXAKTEN JSON-Format
(kein Text außerhalb des JSON!):

{
  "score": 0,
  "feedback": "Ausführliches, konstruktives Feedback im Markdown-Format"
}

BEACHTE:
- score: Ganzzahl zwischen 0 und 100
- feedback: Markdown-formatiert
- konstruktiv, motivierend, sachlich
- keine Musterlösungen
- keine zusätzlichen Inhalte
`.trim();

return [
  {
    json: {
      categoryId,
      systemPrompt,
      userPrompt,
      timestamp: new Date().toISOString()
    }
  }
];

// 1) Rohtext IMMER als String holen (robust)
let aiResponseRaw =
  $input.first().json?.message?.content ??
  $input.first().json?.content ??
  $input.first().json?.text ??
  $input.first().json?.message?.text ??
  '';

if (typeof aiResponseRaw !== 'string') aiResponseRaw = String(aiResponseRaw ?? '');
if (!aiResponseRaw.trim()) {
  throw new Error(
    'Leere oder ungültige AI Response:\n' +
    JSON.stringify($input.first().json, null, 2)
  );
}

// 2) JSON aus Code-Fences extrahieren ODER aus { ... } Block
function extractJsonCandidate(raw) {
  // ```json ... ```
  let m = raw.match(/```json\s*([\s\S]*?)\s*```/i);
  if (m?.[1]) return m[1].trim();

  // ``` ... ```
  m = raw.match(/```\s*([\s\S]*?)\s*```/);
  if (m?.[1]) return m[1].trim();

  // Fallback: erstes { bis letztes }
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    return raw.slice(start, end + 1).trim();
  }

  return raw.trim();
}

let aiResponse = extractJsonCandidate(aiResponseRaw);

// 3) Helper: Control-Chars innerhalb von JSON-Strings escapen (fix für "Bad control character")
function escapeControlCharsInsideStrings(input) {
  let out = '';
  let inString = false;
  let escaped = false;

  for (let i = 0; i < input.length; i++) {
    const ch = input[i];
    const code = ch.charCodeAt(0);

    if (!inString) {
      if (ch === '"') inString = true;
      out += ch;
      continue;
    }

    if (escaped) {
      out += ch;
      escaped = false;
      continue;
    }

    if (ch === '\\') {
      out += ch;
      escaped = true;
      continue;
    }

    if (ch === '"') {
      out += ch;
      inString = false;
      continue;
    }

    // 0x00-0x1F sind in JSON-Strings verboten -> escapen
    if (code >= 0x00 && code <= 0x1F) {
      switch (ch) {
        case '\n': out += '\\n'; break;
        case '\r': out += '\\r'; break;
        case '\t': out += '\\t'; break;
        case '\b': out += '\\b'; break;
        case '\f': out += '\\f'; break;
        default:
          out += '\\u' + code.toString(16).padStart(4, '0');
      }
      continue;
    }

    out += ch;
  }

  return out;
}

// 4) Parse mit Fallback
let evaluationData;
try {
  evaluationData = JSON.parse(aiResponse);
} catch (e1) {
  try {
    evaluationData = JSON.parse(escapeControlCharsInsideStrings(aiResponse));
  } catch (e2) {
    throw new Error(
      `Fehler beim Parsen der AI Response: ${e2.message}\n\n` +
      `--- Extracted Candidate ---\n${aiResponse}\n\n` +
      `--- Raw Response ---\n${aiResponseRaw}`
    );
  }
}

// 5) Validierung
if (evaluationData?.score === undefined) {
  throw new Error('AI Response fehlt "score"\n\n' + JSON.stringify(evaluationData, null, 2));
}
if (typeof evaluationData.feedback !== 'string' || !evaluationData.feedback.trim()) {
  throw new Error('AI Response fehlt "feedback" (string)\n\n' + JSON.stringify(evaluationData, null, 2));
}

// 6) Score normalisieren + validieren
const score = Number.parseInt(String(evaluationData.score), 10);
if (!Number.isFinite(score) || score < 0 || score > 100) {
  throw new Error(`Ungültiger Score: ${evaluationData.score}`);
}

// 7) Ergebnis
return [{
  json: {
    success: true,
    score,
    feedback: evaluationData.feedback,
    timestamp: new Date().toISOString()
  }
}];

// Error Handling
const error = $input.item.json.error || $input.all()[0].json.error;

return [{
  json: {
    success: false,
    error: error?.message || 'Unbekannter Fehler bei der Code-Bewertung',
    timestamp: new Date().toISOString()
  }
}];
